def most_common_word(text):
    if not text or text.strip() == '':
        return None

    # Usuń wybrane znaki interpunkcyjne na końcach słów
    words = []
    for token in text.split():
        word = token.strip('.,!?').lower()
        if word:
            words.append(word)

    if not words:
        return None

    counts = {}
    for w in words:
        counts[w] = counts.get(w, 0) + 1

    # Wybierz słowo z największą liczbą wystąpień; w razie remisu wybieramy pierwsze napotkane
    best_word = None
    best_count = 0
    for w in words:
        if counts[w] > best_count:
            best_count = counts[w]
            best_word = w

    return best_word
```

