    parts = expr.split('+')
    total = 0
    for part in parts:
        total += _parse_number_or_var(part, env)
    return total

def execute_sequence(lines):
    env = {}
    outputs = []
    for line in lines:
        line = line.strip()
        if not line:
            continue
        if line.startswith('print(') and line.endswith(')'):
            inner = line[len('print('):-1].strip()
            val = _eval_expr(inner, env)
            outputs.append(val)
        elif '=' in line:
            var, expr = line.split('=', 1)
            var = var.strip()
            val = _eval_expr(expr, env)
            env[var] = val
        else:
            raise ValueError('Nieznana instrukcja: ' + line)
    return outputs
