def rle(s):
    if not s:
        return ''
    i = 0
    result = []
    while i < len(s):
        ch = s[i]
        count = 1
        i += 1
        while i < len(s) and s[i] == ch:
            count += 1
            i += 1
        result.append(f"{ch}{count}")
    return ''.join(result)
